import{_ as i,c as r,b as n,w as e,S as o,a,o as t,d,e as l,r as h}from"./app.80007782.js";const k=JSON.parse('{"title":"\u{1F4CA} Dashboard Module","description":"","frontmatter":{},"headers":[{"level":2,"title":"\u{1F31F} Key Features","slug":"\u{1F31F}-key-features","link":"#\u{1F31F}-key-features","children":[{"level":3,"title":"Role-Based Dashboards","slug":"role-based-dashboards","link":"#role-based-dashboards","children":[]},{"level":3,"title":"Real-Time Analytics","slug":"real-time-analytics","link":"#real-time-analytics","children":[]},{"level":3,"title":"Customizable Widgets","slug":"customizable-widgets","link":"#customizable-widgets","children":[]}]},{"level":2,"title":"\u{1F4A1} Use Cases","slug":"\u{1F4A1}-use-cases","link":"#\u{1F4A1}-use-cases","children":[{"level":3,"title":"For Students","slug":"for-students","link":"#for-students","children":[]},{"level":3,"title":"For Teachers","slug":"for-teachers","link":"#for-teachers","children":[]},{"level":3,"title":"For Administrators","slug":"for-administrators","link":"#for-administrators","children":[]}]},{"level":2,"title":"\u{1F5A5}\uFE0F Technical Implementation","slug":"\u{1F5A5}\uFE0F-technical-implementation","link":"#\u{1F5A5}\uFE0F-technical-implementation","children":[]},{"level":2,"title":"\u{1F504} Integration Points","slug":"\u{1F504}-integration-points","link":"#\u{1F504}-integration-points","children":[]},{"level":2,"title":"\u2699\uFE0F Configuration Options","slug":"\u2699\uFE0F-configuration-options","link":"#\u2699\uFE0F-configuration-options","children":[]},{"level":2,"title":"\u{1F680} Getting Started with the Dashboard","slug":"\u{1F680}-getting-started-with-the-dashboard","link":"#\u{1F680}-getting-started-with-the-dashboard","children":[]}],"relativePath":"en/modules/dashboard-module.md","lastUpdated":1744659307000}'),c={name:"en/modules/dashboard-module.md"},u=a('<h1 id="\u{1F4CA}-dashboard-module" tabindex="-1">\u{1F4CA} Dashboard Module <a class="header-anchor" href="#\u{1F4CA}-dashboard-module" aria-hidden="true">#</a></h1><p>The UniTrack Dashboard module serves as the central hub for all users, providing a personalized overview of the educational institution based on the user&#39;s role and permissions.</p><h2 id="\u{1F31F}-key-features" tabindex="-1">\u{1F31F} Key Features <a class="header-anchor" href="#\u{1F31F}-key-features" aria-hidden="true">#</a></h2><h3 id="role-based-dashboards" tabindex="-1">Role-Based Dashboards <a class="header-anchor" href="#role-based-dashboards" aria-hidden="true">#</a></h3><p>The dashboard adapts to display relevant information based on user roles:</p><ul><li><strong>Student Dashboard</strong>: Shows course schedule, upcoming assignments, recent grades, and attendance statistics</li><li><strong>Teacher Dashboard</strong>: Provides class lists, upcoming lessons, marking tasks, and student performance metrics</li><li><strong>Administrator Dashboard</strong>: Displays institution-wide analytics, user management tools, and system status</li></ul><p><img src="https://via.placeholder.com/800x450?text=UniTrack+Dashboard" alt="Dashboard Overview"></p><h3 id="real-time-analytics" tabindex="-1">Real-Time Analytics <a class="header-anchor" href="#real-time-analytics" aria-hidden="true">#</a></h3><p>The dashboard presents real-time data visualizations to help users make informed decisions:</p><ul><li><strong>Performance Metrics</strong>: Grade distribution charts, attendance trends, and comparative analysis</li><li><strong>Resource Utilization</strong>: Classroom occupancy, faculty workload, and system usage statistics</li><li><strong>Institutional KPIs</strong>: Enrollment rates, academic performance, and student retention metrics</li></ul><h3 id="customizable-widgets" tabindex="-1">Customizable Widgets <a class="header-anchor" href="#customizable-widgets" aria-hidden="true">#</a></h3><p>Users can personalize their dashboard experience:</p><ul><li><strong>Widget Library</strong>: Choose from a variety of information displays and tools</li><li><strong>Layout Customization</strong>: Drag-and-drop interface for arranging widgets</li><li><strong>Saved Configurations</strong>: Multiple dashboard layouts for different tasks or focuses</li></ul><h2 id="\u{1F4A1}-use-cases" tabindex="-1">\u{1F4A1} Use Cases <a class="header-anchor" href="#\u{1F4A1}-use-cases" aria-hidden="true">#</a></h2><h3 id="for-students" tabindex="-1">For Students <a class="header-anchor" href="#for-students" aria-hidden="true">#</a></h3>',15),g=a('<h3 id="for-teachers" tabindex="-1">For Teachers <a class="header-anchor" href="#for-teachers" aria-hidden="true">#</a></h3><p>The dashboard helps teachers manage their daily responsibilities by providing:</p><ul><li>Quick access to class rosters and student profiles</li><li>Tools for recording attendance and inputting grades</li><li>Calendar view of teaching schedule and academic events</li><li>Notification system for student submissions and academic issues</li></ul><h3 id="for-administrators" tabindex="-1">For Administrators <a class="header-anchor" href="#for-administrators" aria-hidden="true">#</a></h3><p>Administrators benefit from comprehensive institutional oversight:</p><ul><li>Bird&#39;s-eye view of academic operations</li><li>User management and permission controls</li><li>System health monitoring and maintenance tools</li><li>Institutional performance analytics and reporting features</li></ul><h2 id="\u{1F5A5}\uFE0F-technical-implementation" tabindex="-1">\u{1F5A5}\uFE0F Technical Implementation <a class="header-anchor" href="#\u{1F5A5}\uFE0F-technical-implementation" aria-hidden="true">#</a></h2><p>The Dashboard module is built using:</p><ul><li><strong>Vue.js</strong> for responsive and interactive frontend components</li><li><strong>Naive UI</strong> for consistent design language and user experience</li><li><strong>Chart.js</strong> for data visualization</li><li><strong>Pinia</strong> for state management</li><li><strong>Real-time data</strong> via WebSocket connections for live updates</li></ul><h2 id="\u{1F504}-integration-points" tabindex="-1">\u{1F504} Integration Points <a class="header-anchor" href="#\u{1F504}-integration-points" aria-hidden="true">#</a></h2><p>The Dashboard module integrates with other UniTrack components:</p><ul><li><strong>Academic Structure Module</strong>: Pulls organizational hierarchy data</li><li><strong>User Management System</strong>: Retrieves role-based permissions and user details</li><li><strong>Grading System</strong>: Displays academic performance metrics</li><li><strong>Attendance Tracking</strong>: Shows presence statistics and trends</li><li><strong>Calendar Module</strong>: Highlights upcoming events and deadlines</li></ul><h2 id="\u2699\uFE0F-configuration-options" tabindex="-1">\u2699\uFE0F Configuration Options <a class="header-anchor" href="#\u2699\uFE0F-configuration-options" aria-hidden="true">#</a></h2><p>Administrators can configure dashboard settings at both system and user levels:</p><table><thead><tr><th>Setting</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td>Default Widgets</td><td>Define standard widgets for each user role</td><td>Role-specific preset</td></tr><tr><td>Refresh Rate</td><td>How often data is updated</td><td>5 minutes</td></tr><tr><td>Data Retention</td><td>How long historical dashboard data is kept</td><td>1 academic year</td></tr><tr><td>Widget Permissions</td><td>Control which widgets are available to which roles</td><td>Role-based access</td></tr></tbody></table><h2 id="\u{1F680}-getting-started-with-the-dashboard" tabindex="-1">\u{1F680} Getting Started with the Dashboard <a class="header-anchor" href="#\u{1F680}-getting-started-with-the-dashboard" aria-hidden="true">#</a></h2><p>For users new to UniTrack, the dashboard offers:</p><ol><li><strong>Guided Tour</strong>: Interactive walkthrough of available features</li><li><strong>Quick Start Cards</strong>: Shortcuts to common actions based on user role</li><li><strong>Notification Center</strong>: Important alerts and system messages</li><li><strong>Search Functionality</strong>: Fast access to people, courses, and resources</li></ol><p>The Dashboard serves as both an information hub and a launchpad to other system features, streamlining the educational management experience for all stakeholders.</p>',19);function m(p,f,b,v,y,_){const s=h("Mermaid");return t(),r("div",null,[u,(t(),n(o,null,{default:e(()=>[d(s,{id:"mermaid-87",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5BStudent%20Login%5D%20--%3E%20B%5BView%20Dashboard%5D%0A%20%20%20%20B%20--%3E%20C%5BCheck%20Schedule%5D%0A%20%20%20%20B%20--%3E%20D%5BView%20Recent%20Grades%5D%0A%20%20%20%20B%20--%3E%20E%5BTrack%20Attendance%5D%0A%20%20%20%20B%20--%3E%20F%5BSee%20Upcoming%20Assignments%5D%0A%20%20%20%20C%20--%3E%20G%5BJoin%20Online%20Class%5D%0A%20%20%20%20D%20--%3E%20H%5BRequest%20Grade%20Review%5D%0A%20%20%20%20E%20--%3E%20I%5BRequest%20Absence%20Justification%5D%0A%20%20%20%20F%20--%3E%20J%5BSubmit%20Assignment%5D%0A"})]),fallback:e(()=>[l(" Loading... ")]),_:1})),g])}const T=i(c,[["render",m]]);export{k as __pageData,T as default};
